<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function psError(m){$('.isi_warning_delete').text(m||'Payslip gagal diproses.');$('.error_data_delete').fadeIn();}
function psMoney(v){return (parseFloat(v||0)||0).toLocaleString('id-ID');}
function psFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),payroll_area:$('#filter_payroll_area').val(),payslip_status:$('#filter_payslip_status').val(),employee_id:$('#filter_employee_id').val(),keyword:$('#filter_keyword').val()};}
function psAjax(s,act,p,parent){$(s).select2({width:'100%',allowClear:true,placeholder:p,dropdownParent:parent||$(document.body),ajax:{url:'<?=base_admin();?>modul/payslip/payslip_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(q){return{term:q.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
function psReset(){$('#form_payslip')[0].reset();$('#payroll_employee_id').val(null).trigger('change');$('#payslip_status').val('GENERATED').trigger('change');$('#release_channel').val('PORTAL').trigger('change');}
$(function(){if($.fn.datepicker){$('.ps-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_payroll_area,#filter_payslip_status,#payslip_status,#release_channel').select2({width:'100%',allowClear:true});psAjax('#filter_employee_id','employee_search','Pilih Employee');psAjax('#payroll_employee_id','payroll_employee_search','Pilih Payroll Result',$('#modal_payslip'));}
var dt=$('#dtb_payslip').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'135px',targets:1}],ajax:{url:'<?=base_admin();?>modul/payslip/payslip_data.php',type:'post',data:function(d){$.extend(d,psFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_generated').text(k.generated||0);$('#kpi_released').text(k.released||0);$('#kpi_voided').text(k.voided||0);$('#kpi_gross').text(psMoney(k.gross));$('#kpi_net').text(psMoney(k.net));return j.data||[];},error:function(x){console.log(x.responseText);psError('Data Payslip gagal dimuat.');}}});
$('#btn_open_ps').click(function(){psReset();$('#modal_payslip').modal({backdrop:'static',keyboard:false});});$('#btn_filter_ps').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_ps').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_payroll_area,#filter_payslip_status,#filter_employee_id').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_ps').click(function(){window.location='<?=base_admin();?>modul/payslip/payslip_action.php?act=export&'+$.param(psFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
$('#form_payslip').submit(function(e){e.preventDefault();var b=$(this).find('button[type=submit]');b.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> Generating...');$.post('<?=base_admin();?>modul/payslip/payslip_action.php?act=generate',$(this).serialize(),function(r){b.prop('disabled',false).html('<i class="fa fa-magic"></i> Generate');if(r.status==='good'){$('#modal_payslip').modal('hide');dt.draw(false);Swal.fire('Generated','Payslip berhasil dibuat.','success');}else psError(r.error_message);},'json').fail(function(x){b.prop('disabled',false).html('<i class="fa fa-magic"></i> Generate');psError(x.responseText);});});
$(document).on('click','.btn-ps-detail',function(){$.post('<?=base_admin();?>modul/payslip/payslip_action.php?act=detail',{id:$(this).data('id')},function(h){$('#ps_detail_body').html(h);$('#modal_ps_detail').modal('show');});});
$(document).on('click','.btn-ps-release',function(){if($(this).is(':disabled'))return;var id=$(this).data('id');$.post('<?=base_admin();?>modul/payslip/payslip_action.php?act=status',{id:id,status:'RELEASED'},function(r){if(r.status==='good'){dt.draw(false);Swal.fire('Released','Payslip berhasil direlease.','success');}else psError(r.error_message);},'json');});
$(document).on('click','.btn-ps-void',function(){if($(this).is(':disabled'))return;var id=$(this).data('id');Swal.fire({title:'Void Payslip?',text:'Slip akan ditandai VOID untuk audit.',icon:'warning',showCancelButton:true,confirmButtonText:'Void'}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/payslip/payslip_action.php?act=status',{id:id,status:'VOID'},function(r){if(r.status==='good'){dt.draw(false);Swal.fire('Voided','Payslip berhasil divoid.','success');}else psError(r.error_message);},'json');});});
$(document).on('click','.btn-ps-delete',function(){if($(this).is(':disabled'))return;var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:erpLang('confirm_delete_title','Delete Confirmation'),text:no,icon:'warning',showCancelButton:true,confirmButtonText:erpLang('common_delete','Delete'),cancelButtonText:erpLang('common_cancel','Cancel')}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/payslip/payslip_action.php?act=delete',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(erpLang('common_deleted','Deleted'),erpLang('common_deleted_message','Data deleted successfully.'),'success');}else psError(r.error_message);},'json');});});
});
</script>
